// 3-way QuickSort (Dutch National Flag) handles duplicates and sorted data efficiently.
void quicksort(std::vector<int>& arr, int low, int high) {
    if (high - low < 16) {
        for (int i = low + 1; i <= high; i++) {
            int t = arr[i], j = i;
            while (j > low && arr[j - 1] > t) { arr[j] = arr[j - 1]; --j; }
            arr[j] = t;
        }
        return;
    }
    int i = low, j = high, k = low, pivot = arr[low + (high - low) / 2];
    while (k <= j) {
        if (arr[k] < pivot) std::swap(arr[i++], arr[k++]);
        else if (arr[k] > pivot) std::swap(arr[j--], arr[k]);
        else k++;
    }
    quicksort(arr, low, i - 1);
    quicksort(arr, j + 1, high);
}

void adaptive_sort(std::vector<int>& arr) {
    int n = static_cast<int>(arr.size());
    if (n < 2) return;
    bool a = 1, d = 1;
    for (int i = 1; i < n; i++) {
        if (arr[i] < arr[i - 1]) a = 0;
        if (arr[i] > arr[i - 1]) d = 0;
    }
    if (a) return;
    if (d) { for (int i = 0; i < n / 2; i++) std::swap(arr[i], arr[n - 1 - i]); return; }
    quicksort(arr, 0, n - 1);
}

